// src/cli/commands/validate.ts
init_esm5();
init_api6();
init_validator();
import * as fs16 from "fs";
import * as path15 from "path";
init_error_utils();
init_agent_rules();
async function validateCommand(input, options = {}) {
  const { verbose = false, quiet = false, workflowName, json: json2 = false, strict = false } = options;
  try {
    let pattern = input;
    try {
      if (fs16.existsSync(input) && fs16.statSync(input).isDirectory()) {
        pattern = path15.join(input, "**/*.ts");
      }
    } catch {
    }
    const allFiles = await glob(pattern, { absolute: true });
    const files = allFiles.filter((f) => {
      try {
        return fs16.statSync(f).isFile();
      } catch {
        return false;
      }
    });
    if (files.length === 0) {
      if (json2) {
        console.log(JSON.stringify({ error: `No files found matching pattern: ${input}` }));
      } else {
        logger.error(`No files found matching pattern: ${input}`);
      }
      process.exit(1);
    }
    if (!json2) {
      logger.section("Validating Workflows");
      logger.info(`Found ${files.length} file(s)`);
      logger.newline();
    }
    let totalErrors = 0;
    let totalWarnings = 0;
    let successCount = 0;
    const jsonResults = [];
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const fileName = path15.basename(file);
      if (!json2) {
        logger.progress(i + 1, files.length, fileName);
      }
      try {
        const parseResult = await parseWorkflow(file, { workflowName });
        if (parseResult.warnings.length > 0) {
          if (!json2 && !quiet) {
            logger.warn(`Parse warnings in ${fileName}:`);
            parseResult.warnings.forEach((w) => logger.warn(`  - ${w}`));
          }
          totalWarnings += parseResult.warnings.length;
        }
        if (parseResult.errors.length > 0) {
          const isNonWorkflowFile = parseResult.errors.length === 1 && typeof parseResult.errors[0] === "string" && parseResult.errors[0].startsWith("No workflows found");
          if (isNonWorkflowFile) {
            if (verbose && !json2) {
              logger.debug(`  Skipped ${fileName} (no workflow)`);
            }
            continue;
          }
          if (json2) {
            jsonResults.push({
              file,
              valid: false,
              errors: parseResult.errors.map(
                (e) => typeof e === "string" ? { message: e, severity: "error" } : e
              ),
              warnings: parseResult.warnings.map(
                (w) => typeof w === "string" ? { message: w, severity: "warning" } : w
              )
            });
          } else {
            logger.error(`Parse errors in ${fileName}:`);
            parseResult.errors.forEach((err) => logger.error(`  ${err}`));
          }
          totalErrors += parseResult.errors.length;
          continue;
        }
        const validation = validator.validate(parseResult.ast, { strictMode: strict });
        const agentRules = getAgentValidationRules();
        for (const rule of agentRules) {
          const ruleErrors = rule.validate(parseResult.ast);
          for (const err of ruleErrors) {
            if (err.type === "warning") {
              validation.warnings.push(err);
            } else {
              validation.errors.push(err);
              validation.valid = false;
            }
          }
        }
        if (json2) {
          jsonResults.push({
            file,
            valid: validation.valid,
            errors: validation.errors.map((e) => ({
              message: e.message,
              severity: e.type || "error",
              ...e.node && { nodeId: e.node },
              ...e.code && { code: e.code }
            })),
            warnings: [
              ...parseResult.warnings.map(
                (w) => typeof w === "string" ? { message: w, severity: "warning" } : w
              ),
              ...validation.warnings.map((w) => ({
                message: w.message,
                severity: w.type || "warning",
                ...w.node && { nodeId: w.node },
                ...w.code && { code: w.code }
              }))
            ]
          });
        }
        if (validation.errors.length > 0) {
          if (!json2) {
            logger.error(`Validation errors in ${fileName}:`);
            validation.errors.forEach((err) => {
              const friendly = getFriendlyError(err);
              if (friendly) {
                const loc = err.location ? `[line ${err.location.line}] ` : "";
                logger.error(`  ${loc}${friendly.title}: ${friendly.explanation}`);
                logger.info(`    How to fix: ${friendly.fix}`);
                if (err.docUrl) {
                  logger.info(`    See: ${err.docUrl}`);
                }
              } else {
                let msg = `  - ${err.message}`;
                if (err.location) {
                  msg = `  [line ${err.location.line}] - ${err.message}`;
                }
                if (err.node) {
                  msg += ` (node: ${err.node})`;
                }
                if (err.connection) {
                  msg += ` (connection: ${err.connection.from.node}:${err.connection.from.port} -> ${err.connection.to.node}:${err.connection.to.port})`;
                }
                logger.error(msg);
                if (err.docUrl) {
                  logger.info(`    See: ${err.docUrl}`);
                }
              }
            });
          }
          totalErrors += validation.errors.length;
        }
        if (validation.warnings.length > 0) {
          if (!json2 && !quiet) {
            logger.warn(`Warnings in ${fileName}:`);
            validation.warnings.forEach((warn) => {
              const friendly = getFriendlyError(warn);
              if (friendly) {
                const loc = warn.location ? `[line ${warn.location.line}] ` : "";
                logger.warn(`  ${loc}${friendly.title}: ${friendly.explanation}`);
                logger.info(`    How to fix: ${friendly.fix}`);
                if (warn.docUrl) {
                  logger.info(`    See: ${warn.docUrl}`);
                }
              } else {
                let msg = `  - ${warn.message}`;
                if (warn.location) {
                  msg = `  [line ${warn.location.line}] - ${warn.message}`;
                }
                if (warn.node) {
                  msg += ` (node: ${warn.node})`;
                }
                logger.warn(msg);
                if (warn.docUrl) {
                  logger.info(`    See: ${warn.docUrl}`);
                }
              }
            });
          }
          totalWarnings += validation.warnings.length;
        }
        if (validation.valid) {
          if (!json2 && verbose) {
            logger.success(`  ${fileName} is valid`);
          }
          successCount++;
        }
      } catch (error2) {
        if (json2) {
          jsonResults.push({
            file,
            valid: false,
            errors: [{ message: getErrorMessage(error2), severity: "error" }],
            warnings: []
          });
        } else {
          logger.error(`Failed to validate ${fileName}: ${getErrorMessage(error2)}`);
        }
        totalErrors++;
      }
    }
    if (json2) {
      console.log(
        JSON.stringify(
          {
            valid: totalErrors === 0,
            totalFiles: files.length,
            validFiles: successCount,
            totalErrors,
            totalWarnings,
            results: jsonResults
          },
          null,
          2
        )
      );
    } else {
      logger.newline();
      logger.section("Validation Summary");
      logger.success(`${successCount} file(s) valid`);
      if (totalWarnings > 0) {
        logger.warn(`${totalWarnings} warning(s) found`);
      }
      if (totalErrors > 0) {
        logger.error(`${totalErrors} error(s) found`);
      } else {
        logger.success("All workflows are valid!");
      }
    }
    if (totalErrors > 0) {
      process.exit(1);
    }
  } catch (error2) {
    if (json2) {
      console.log(JSON.stringify({ error: getErrorMessage(error2) }));
    } else {
      logger.error(`Validation failed: ${getErrorMessage(error2)}`);
    }
    process.exit(1);
  }
}

