function parseEventFilterFromEnv() {
  const filter3 = {};
  const include = process.env.FW_EVENT_INCLUDE;
  if (include) {
    filter3.include = include.split(",").map((s) => s.trim()).filter(Boolean);
  }
  const exclude = process.env.FW_EVENT_EXCLUDE;
  if (exclude) {
    filter3.exclude = exclude.split(",").map((s) => s.trim()).filter(Boolean);
  }
  const dedupeMs = process.env.FW_EVENT_DEDUPE_MS;
  if (dedupeMs) {
    const parsed = parseInt(dedupeMs, 10);
    if (!isNaN(parsed)) filter3.dedupeWindowMs = parsed;
  }
  const maxBuf = process.env.FW_EVENT_MAX;
  if (maxBuf) {
    const parsed = parseInt(maxBuf, 10);
    if (!isNaN(parsed)) filter3.maxBufferSize = parsed;
  }
  return filter3;
}
async function startMcpServer(options) {
  const serverUrl = options.server || DEFAULT_SERVER_URL;
  const filterFromEnv = parseEventFilterFromEnv();
  const buffer = options._testDeps?.buffer ?? new EventBuffer(void 0, void 0, filterFromEnv);
  const connection = options._testDeps?.connection ?? new EditorConnection(serverUrl, buffer);
  if (!options._testDeps) {
    const log = options.stdio ? (msg) => process.stderr.write(msg + "\n") : (
      // eslint-disable-next-line no-console
      (msg) => console.log(msg)
    );
    connection.connect(log);
  }
  const mcp = new McpServer({
    name: "flow-weaver",
    version: "1.0.0"
  });
  registerEditorTools(mcp, connection, buffer);
  registerQueryTools(mcp);
  registerTemplateTools(mcp);
  registerPatternTools(mcp);
  registerExportTools(mcp);
  registerMarketplaceTools(mcp);
  registerDiagramTools(mcp);
  registerDocsTools(mcp);
  registerModelTools(mcp);
  registerDebugTools(mcp);
  registerContextTools(mcp);
  registerResources(mcp, connection, buffer);
  registerPrompts(mcp);
  if (!options._testDeps && options.stdio) {
    const transport = new StdioServerTransport();
    await mcp.connect(transport);
  }
}
async function mcpServerCommand(options) {
  const serverUrl = options.server || DEFAULT_SERVER_URL;
  const log = options.stdio ? (msg) => process.stderr.write(msg + "\n") : (msg) => process.stdout.write(msg + "\n");
  if (!options.stdio) {
    log('Tip: run "flow-weaver mcp-setup" to register with your AI tools.');
    log(`Starting MCP server (Studio: ${serverUrl})...`);
  }
  await startMcpServer(options);
  if (!options.stdio) {
    log("MCP server running. Waiting for connections...");
  }
  await new Promise(() => {
  });
}

